srcDoc.css:
* {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

body {
  background: transparent;
  display: flex;
  align-items: center;
  height: 100%;
  font-family: Inter, system-ui, sans-serif;
  overflow: hidden;
}

#bc {
  display: flex;
  align-items: center;
  gap: 6px;
  font-size: 20px;
}

.bc-link {
  color: #1A5C3A;
  cursor: pointer;
  font-weight: 500;
  padding: 2px 0;
}

.bc-link:hover {
  text-decoration: underline;
}

.bc-sep {
  color: #9CA3AF;
}

.bc-current {
  color: #1A1A2E;
  font-weight: 600;
}

srcDoc.js:
appsmith.onReady(function () {
  render();
});
appsmith.onModelChange(function () {
  render();
});
function render() {
  var model = appsmith.model;
  var collectionId = model.collectionId || '';
  var customerName = model.customerName || '';
  var barcode = model.barcode || '';
  var assetsLabel = model.assetsLabel || 'Assets';
  var bc = document.getElementById('bc');
  bc.innerHTML = '<span class="bc-link" onclick="goAssets()">' + assetsLabel + '</span>' + '<span class="bc-sep">›</span>' + '<span class="bc-link" onclick="goCollection()">Collection ' + collectionId + ' · ' + customerName + '</span>' + '<span class="bc-sep">›</span>' + '<span class="bc-current">' + barcode + '</span>';
}
function goAssets() {
  appsmith.triggerEvent('goAssets');
}
function goCollection() {
  appsmith.triggerEvent('goCollection');
}

